 1	import React from 'react';
 2	
 3	import MigrationPolicyModel from '@kubevirt-ui/kubevirt-api/console/models/MigrationPolicyModel';
 4	import { V1alpha1MigrationPolicy } from '@kubevirt-ui/kubevirt-api/kubevirt';
 5	import { LabelsModal } from '@kubevirt-utils/components/LabelsModal/LabelsModal';
 6	import { useModal } from '@kubevirt-utils/components/ModalProvider/ModalProvider';
 7	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 8	import { isEmpty } from '@kubevirt-utils/utils/utils';
 9	import { k8sUpdate } from '@openshift-console/dynamic-plugin-sdk';
10	import {
11	  Button,
12	  ButtonVariant,
13	  DescriptionListDescription,
14	  DescriptionListGroup,
15	  DescriptionListTermHelpText,
16	  LabelGroup,
17	} from '@patternfly/react-core';
18	
19	import { MigrationPolicySelectorList } from '../../../../../../components/MigrationPolicySelectorList/MigrationPolicySelectorList';
20	import { ensureMigrationPolicyMatchLabels } from '../utils/utils';
21	
22	type MigrationPolicyVirtualMachineLabelsProps = {
23	  mp: V1alpha1MigrationPolicy;
24	};
25	const MigrationPolicyVirtualMachineLabels: React.FC<MigrationPolicyVirtualMachineLabelsProps> = ({
26	  mp,
27	}) => {
28	  const { t } = useKubevirtTranslation();
29	  const { createModal } = useModal();
30	
31	  const mpNamespaceSelector = mp?.spec?.selectors?.namespaceSelector;
32	
33	  return (
34	    <DescriptionListGroup>
35	      <DescriptionListTermHelpText className="migration-policy-description-item-header">
36	        {t('Project labels')}
37	        <Button
38	          onClick={() =>
39	            createModal(({ isOpen, onClose }) => (
40	              <LabelsModal
41	                onLabelsSubmit={(labels) =>
42	                  k8sUpdate({
43	                    data: ensureMigrationPolicyMatchLabels(mp, labels, 'namespaceSelector'),
44	                    model: MigrationPolicyModel,
45	                  })
46	                }
47	                initialLabels={mpNamespaceSelector}
48	                isOpen={isOpen}
49	                obj={mp}
50	                onClose={onClose}
51	              />
52	            ))
53	          }
54	          className="migration-policy-description-item-header--action-button"
55	          isInline
56	          variant={ButtonVariant.link}
57	        >
58	          {t('Edit')}
59	        </Button>
60	      </DescriptionListTermHelpText>
61	      <DescriptionListDescription>
62	        {!isEmpty(mpNamespaceSelector) && (
63	          <LabelGroup className="migration-policy-selectors-group" isEditable>
64	            <MigrationPolicySelectorList selector={mpNamespaceSelector} />
65	          </LabelGroup>
66	        )}
67	      </DescriptionListDescription>
68	    </DescriptionListGroup>
69	  );
70	};
71	
72	export default MigrationPolicyVirtualMachineLabels;

